import{c as n}from"./app.8935f5f1.js";const s={},a=n('<ul><li><p><strong>字符流和字节流：</strong></p><ul><li><p>字节流两个基类： <code>InputStream OutputStream</code></p></li><li><p>字符流两个基类： <code>Reader Writer</code></p></li></ul></li></ul><p>既然IO流是用于操作数据的， 那么数据的最常见体现形式是：文件。</p><ul><li><strong>fileWriter</strong></li></ul><div class="language-java ext-java"><pre class="language-java"><code>\t<span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">IOException</span>\n\t<span class="token punctuation">{</span>\n\t\t<span class="token comment">//创建一个FileWriter对象。该对象一被初始化就必须要明确被操作的文件。</span>\n\t\t<span class="token comment">//而且该文件会被创建到指定目录下。如果该目录下已有同名文件，将被覆盖。</span>\n\t\t<span class="token comment">//其实该步就是在明确数据要存放的目的地。</span>\n\t\t<span class="token class-name">FileWriter</span> fw <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileWriter</span><span class="token punctuation">(</span><span class="token string">&quot;demo.txt&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\t\t<span class="token comment">//调用write方法，将字符串写入到流中。</span>\n\t\tfw<span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span><span class="token string">&quot;abcde&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\t\t<span class="token comment">//刷新流对象中的缓冲中的数据。</span>\n\t\t<span class="token comment">//将数据刷到目的地中。</span>\n\t\t<span class="token comment">//fw.flush();</span>\n\n\n\t\t<span class="token comment">//关闭流资源，但是关闭之前会刷新一次内部的缓冲中的数据。</span>\n\t\t<span class="token comment">//将数据刷到目的地中。</span>\n\t\t<span class="token comment">//和flush区别：flush刷新后，流可以继续使用，close刷新后，会将流关闭。</span>\n\t\tfw<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\t<span class="token punctuation">}</span>\n\n\n\n    <span class="token comment">//传递一个true参数，代表不覆盖已有的文件。并在已有文件的末尾处进行数据续写。</span>\n\t\t<span class="token class-name">FileWriter</span> fw <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileWriter</span><span class="token punctuation">(</span><span class="token string">&quot;demo.txt&quot;</span><span class="token punctuation">,</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\t\tfw<span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span><span class="token string">&quot;nihao\\r\\nxiexie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\t\tfw<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n        \n</code></pre></div><ul><li><strong>fileReader</strong></li></ul><div class="language-java ext-java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token keyword">throws</span> <span class="token class-name">IOException</span>\n\t<span class="token punctuation">{</span>\n\t\t<span class="token comment">//创建一个文件读取流对象，和指定名称的文件相关联。</span>\n\t\t<span class="token comment">//要保证该文件是已经存在的，如果不存在，会发生异常FileNotFoundException</span>\n\t\t<span class="token class-name">FileReader</span> fr <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">FileReader</span><span class="token punctuation">(</span><span class="token string">&quot;demo.txt&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\t\t<span class="token comment">//调用读取流对象的read方法。</span>\n\t\t<span class="token comment">//read():一次读一个字符。而且会自动往下读。</span>\n\t\t\n\t\t<span class="token keyword">int</span> ch <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>\n\n\t\t<span class="token keyword">while</span><span class="token punctuation">(</span><span class="token punctuation">(</span>ch<span class="token operator">=</span>fr<span class="token punctuation">.</span><span class="token function">read</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token operator">!=</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span>\n\t\t<span class="token punctuation">{</span>\n\t\t\t<span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>\n\t\t<span class="token punctuation">}</span>\n\n\n\t\t<span class="token comment">/*\n\t\twhile(true)\n\t\t{\n\t\t\tint ch = fr.read();\n\t\t\tif(ch==-1)\n\t\t\t\tbreak;\n\t\t\tSystem.out.println(&quot;ch=&quot;+(char)ch);\n\t\t}\n\t\t*/</span>\n\n\n\n\t\tfr<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n\n\t<span class="token punctuation">}</span>\n</code></pre></div>',6);s.render=function(n,s){return a};export{s as default};
